    useEffect(() => {
        const fetchDocs = async () => {
            const data = await getUserDocuments(user.username);
            setDocs(data);
        };
        fetchDocs();
    }, [user.username]);

    // FIX: addUserDocument is async, mark handler as async and await result.
    const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            const file = e.target.files[0];
            const newDoc = await addUserDocument(user.username, file);
            setDocs(prev => [newDoc, ...prev]);
        }
    };

    // FIX: deleteUserDocument is async, mark handler as async and await result.
    const handleDeleteDoc = async (id: string) => {
        await deleteUserDocument(user.username, id);
        setDocs(prev => prev.filter(d => d.id !== id));
