// --- Property Management ---
export const getProperties = async (): Promise<Property[]> => {
    try {
        const { data, error } = await supabase
            .from('properties')
            .select('*')
            .order('date_listed', { ascending: false });

        if (error) {
            handleError(error, 'Error fetching properties');
            return initialProperties; // Fallback to mock data on DB error
        }

        if (!data || data.length === 0) {
            // Seed if empty (one-time or for demo)
            try {
                const seedData = initialProperties.map(p => ({
                    id: p.id,
                    title: p.title,
                    listing_type: p.listingType,
                    property_type: p.propertyType,
                    address: p.address,
                    coordinates: p.coordinates,
                    price: p.price,
                    purchase_price: p.purchasePrice,
                    details: p.details,
                    description: p.description,
                    neighborhood_info: p.neighborhoodInfo,
                    amenities: p.amenities,
                    images: p.images,
                    virtual_tour_url: p.virtualTourUrl,
                    vr_tour_url: p.vrTourUrl,
                    agent: p.agent,
                    featured: p.featured,
                    verified: p.verified,
                    smart_contract_ready: p.smartContractReady,
                    views: p.views,
                    status: p.status,
                    date_listed: p.dateListed,
                    saves: p.saves,
                    price_history: p.priceHistory,
                    occupancy_rate: p.occupancyRate,
                    market_roi: p.marketROI,
                    financials: p.financials,
                    guests: p.guests,
                    vehicle_type: p.vehicleType,
                    package_includes: p.packageIncludes,
                    per_night_price: p.perNightPrice
                }));
                const { error: seedError } = await supabase.from('properties').insert(seedData);
                if (seedError) handleError(seedError, "Seeding properties failed");
            } catch (seedErr) {
                console.warn("Seeding properties failed (likely table doesn't exist):", seedErr);
            }
            return initialProperties;
        }

        return data.map(p => ({
            ...p,
            dateListed: p.date_listed,
            listingType: p.listing_type,
            propertyType: p.property_type,
            purchasePrice: p.purchase_price,
            neighborhoodInfo: p.neighborhood_info,
            virtualTourUrl: p.virtual_tour_url,
            vrTourUrl: p.vr_tour_url,
            smartContractReady: p.smart_contract_ready,
            priceHistory: p.price_history,
            occupancyRate: p.occupancy_rate,
            marketROI: p.market_roi,
            perNightPrice: p.per_night_price,
            packageIncludes: p.package_includes,
            vehicleType: p.vehicle_type
        }));
    } catch (criticalErr) {
        console.error("Critical error in getProperties:", criticalErr);
        return initialProperties;
    }
};

export const saveProperties = async (properties: Property[]): Promise<void> => {
    const { error } = await supabase.from('properties').upsert(properties.map(p => ({
        ...p,
        date_listed: p.dateListed,
        listing_type: p.listingType,
        property_type: p.propertyType
    })));
    handleError(error, 'Error upserting properties');
};

export const incrementPropertyView = async (propertyId: string): Promise<void> => {
    const { error } = await supabase.rpc('increment_views', { prop_id: propertyId });
    if (error) {
        // Fallback if RPC isn't set up
        const { data: prop } = await supabase.from('properties').select('views').eq('id', propertyId).single();
        if (prop) {
            await supabase.from('properties').update({ views: (prop.views || 0) + 1 }).eq('id', propertyId);
        }
    }
};

// --- User Management ---
export const getUsers = async (): Promise<User[]> => {
    const { data, error } = await supabase.from('profiles').select('*');
    handleError(error, 'Error fetching users');
    return data || [];
};

export const addUser = async (user: User): Promise<{ success: boolean, message: string }> => {
    const { error } = await supabase.from('profiles').insert({
        ...user,
        is_verified: user.role === 'user'
    });
    if (error) return { success: false, message: error.message };
    return { success: true, message: "User created successfully." };
};

export const authenticateUser = async (email: string, password: string): Promise<{ user: User | null; error?: string }> => {
    const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('email', email)
        .eq('password', password)
        .single();

    if (error || !data) return { user: null, error: 'Invalid email or password.' };

    if ((data.role === 'agent' || data.role === 'investor') && !data.is_verified) {
        return { user: null, error: `pending_verification_${data.role}` };
    }

    return { user: data };
};

